class Solution:
    def minimumDeletions(self, nums):
        n = len(nums)
        lo_val = min(nums)
        hi_val = max(nums)
        best = n
        for f in range(n + 1):
            for b in range(n - f + 1):
                remaining = nums[f:n - b] if b > 0 else nums[f:]
                if lo_val not in remaining and hi_val not in remaining:
                    best = min(best, f + b)
        return best

