class Solution:
    def minimumDeletions(self, nums):
        n = len(nums)
        i = nums.index(min(nums))
        j = nums.index(max(nums))
        lo, hi = min(i, j), max(i, j)
        front_only = hi + 1
        back_only = n - lo
        both_ends = (lo + 1) + (n - hi)
        return min(front_only, back_only, both_ends)

