var minimumDeletions = function(nums) {
    const n = nums.length;
    let minVal = nums[0], maxVal = nums[0];
    for (const v of nums) {
        if (v < minVal) minVal = v;
        if (v > maxVal) maxVal = v;
    }
    const i = nums.indexOf(minVal);
    const j = nums.indexOf(maxVal);
    const lo = Math.min(i, j), hi = Math.max(i, j);
    const frontOnly = hi + 1;
    const backOnly = n - lo;
    const bothEnds = (lo + 1) + (n - hi);
    return Math.min(frontOnly, backOnly, bothEnds);
};
